/**
 * CLI: read study graph snapshot JSON from stdin or file, exit 0 iff validate passes.
 */
import * as fs from 'node:fs';
import { validateStudyGraphSnapshot } from '../src/study-graph-snapshot';

function main(): void {
  const path = process.argv[2];
  const raw =
    path === undefined || path === '-'
      ? fs.readFileSync(0, 'utf8')
      : fs.readFileSync(path, 'utf8');
  let json: unknown;
  try {
    json = JSON.parse(raw) as unknown;
  } catch {
    process.stderr.write('study-snapshot: invalid JSON\n');
    process.exit(1);
  }
  const r = validateStudyGraphSnapshot(json);
  if (!r.ok) {
    process.stderr.write(`study-snapshot: ${r.reason}\n`);
    process.exit(1);
  }
  process.stdout.write('study-snapshot: ok\n');
  process.exit(0);
}

main();
